function OpenModal() {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isModal2Open, setIsModal2Open] = useState(false);
    const [hashtagColor, setHashtagColor] = useState("#48484e");

    const openModal = () => {
        setIsModalOpen(true);
    };

    const closeModal = () => {
        setIsModalOpen(false);
    };

    const openModal2 = () => {
        setIsModal2Open(true);
    };

    const closeModal2 = () => {
        setIsModal2Open(false);
    };

    const handleHashtagClick = () => {
        setHashtagColor(prevColor => prevColor === "#48484e" ? "#6d9af2" : "#48484e");
    };

    return (
        <div>
            <button id="add_a_new_post_button" onClick={openModal}>Open Modal</button>

            {isModalOpen && (
                <div id="modal">
                    <button id="close-button" onClick={closeModal}>Close Modal</button>
                    <button id="modal_img4" onClick={openModal2}>Open Modal 2</button>
                </div>
            )}

            {isModal2Open && (
                <div id="modal2">
                    <button id="close-button2" onClick={closeModal2}>Close Modal 2</button>
                    <button id="modal2_save_button" onClick={closeModal2}>Save</button>
                    <div id="modal2_hashtag1" style={{ backgroundColor: hashtagColor }} onClick={handleHashtagClick}>Hashtag</div>
                </div>
            )}

            {isModalOpen && <div id="overlay"></div>}
        </div>
    );
}




function ImageUploader() {
    const [selectedFile, setSelectedFile] = useState(null);

    const handleFileChange = (event) => {
        const file = event.target.files[0];
        if (file) {
            setSelectedFile(URL.createObjectURL(file));
        }
    };

    return (
        <div>
            <input type="file" accept="image/*" onChange={handleFileChange} />
            {selectedFile && (
                <img src={selectedFile} alt="Selected" style={{ maxHeight: "100%", maxWidth: "100%" }} />
            )}
        </div>
    );
}

export {ImageUploader, OpenModal};


